import{_ as e,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const P=JSON.parse('{"title":"11.魔术师的算法清单","description":"","frontmatter":{},"headers":[],"relativePath":"5.撰写相关/11.魔术师的算法清单.md","filePath":"5.撰写相关/11.魔术师的算法清单.md"}'),s={name:"5.撰写相关/11.魔术师的算法清单.md"};function _(d,a,o,l,D,i){return t(),p("div",null,[...a[0]||(a[0]=[r("h1",{id:"_11-魔术师的算法清单",tabindex:"-1"},[b("11.魔术师的算法清单 "),r("a",{class:"header-anchor",href:"#_11-魔术师的算法清单","aria-label":'Permalink to "11.魔术师的算法清单"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),n('<h1 id="魔术师的算法清单" tabindex="-1">魔术师的算法清单 <a class="header-anchor" href="#魔术师的算法清单" aria-label="Permalink to &quot;魔术师的算法清单&quot;">​</a></h1><p>烧伤 每点算法：<br> S=a/(1-r）=3/（1-2/3）=9DP<br> 破裂/沉沦/震颤 每点算法：<br> S=a/(1-r）=3/（1-1/2）=6DP<br> 充能 每点算法：<br> 固定充能 1.5DP1点<br> 本质为存储1DP，在一场景内可以选择使用一次。<br> 非固定充能走轮次成长一次性DP<br> 烟气 每点算法：<br> D4.5 C5.2 B6 A8 S9</p><p>轮次成长一次性DP：<br> 长出1DP按2DP使用，用后销毁</p><p>困难地形变体用法：<br> 使用困难地形挂负面状态无法进行豁免，在持续处于地形一轮后才会受到影响，固定敌我不分，地形无法移动。<br> 可将困难地形从圆形转化为线形，线的厚度视为无，长度挂靠一次移动。</p><p>类了如指掌能力：<br> 看到一件物品，得知其名称和一种用法 D特<br> 看到一件物品，得知其真正名称和一种详细用法 C特</p><p>类招架能力：<br> 反击 <br> 效果：招架时不进行招架，而是准备一次反击，受到攻击时立即进行反击，反击伤害等同于获得的招架伤害抵销数，这些伤害只能被吸收<br> 价格：所有类招架都是C特，不一一列举</p><p>反伤 第1点反伤6DP，此后每1点反伤3DP，必须基于受到一次攻击，注意结合画风，如近战反伤远程需画风合理</p><p>活体护甲 在购买第1点之后，每1点需交1税<br> 花招动作的DP转换</p><p>理论上1D特能买到一个花招动作，但是不要直接给花招动作，也不要给AP。理论上消耗一个花招动作可以换取1.5DP</p><p>类毁灭/湮灭（咱就是说TMD的类特性替换是真多）不能与毁灭/湮灭同时生效，1倍权值，视为具有保底能力</p><p>模因传播 3B特 前置要求传奇表演，根据不同层次划分DC调整，基础按照等级固定DC，传播范围是不大于城 传播结果：了解并相信思想<br> 后继有人：2S特 解除传播范围限制 传播结果：依照思想成为一类特殊人群</p><p>类造物获得物品：严格进行一次造物，可以享受造物的价格减免<br> 曾经可以使用的变体：不减少而是额外提供DP</p><p>死亡无法复活4倍限制权值，可以复活无权值<br> 先攻比敌人高，对于那个敌人而言获得0.5限制权值<br> 准确预言对方造成的伤害量时触发的效果，对于那次攻击而言获得2限制权值<br> 某次攻击完全不造成伤害触发的效果，对于那个效果而言获得1限制权值</p><p>拔刀检定的计算方式：<br> 拔刀检定是一个不计入其他属性加值但可计入全检定或是意志力用法的检定，其价格为纯属性计算期望加上1/3的步长算法的1/3，也就是说，进行一次拔刀检定，获得Xdp的价格，在D级开始算是（（6+11+16+21+26）/3）/5+（1+2+3+4+5）/5+23.15/3=8.33+7.71=16dp。这是对于额外购买的基于拔刀检定的能力而言的价格。需要注意的是，这一类加值请尽量以武器进行购买。所购买的DP数量尽量控制在每拔刀检定成功数获得1-1.5dp左右。再就是，避免挂钩一系列恢复能力。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',16)])])}const h=e(s,[["render",_]]);export{P as __pageData,h as default};
